import{_ as e,c as a,o,a as i}from"./app.ae51eafc.js";const f=JSON.parse('{"title":"Pila del Producto","description":"","frontmatter":{},"headers":[{"level":2,"title":"Preparaci\xF3n de la Pila del Producto","slug":"preparacion-de-la-pila-del-producto","link":"#preparacion-de-la-pila-del-producto","children":[]},{"level":2,"title":"Formato de la Pila del Producto","slug":"formato-de-la-pila-del-producto","link":"#formato-de-la-pila-del-producto","children":[]},{"level":2,"title":"Id","slug":"id","link":"#id","children":[]},{"level":2,"title":"Grado de Importancia","slug":"grado-de-importancia","link":"#grado-de-importancia","children":[]},{"level":2,"title":"Descripci\xF3n","slug":"descripcion","link":"#descripcion","children":[]},{"level":2,"title":"Esfuerzo que demanda","slug":"esfuerzo-que-demanda","link":"#esfuerzo-que-demanda","children":[]},{"level":2,"title":"Granulidad de los Items","slug":"granulidad-de-los-items","link":"#granulidad-de-los-items","children":[]},{"level":2,"title":"Criterios de Aceptaci\xF3n","slug":"criterios-de-aceptacion","link":"#criterios-de-aceptacion","children":[]},{"level":2,"title":"Notas (Observaci\xF3n)","slug":"notas-observacion","link":"#notas-observacion","children":[]},{"level":2,"title":"Campos adicionales del formato","slug":"campos-adicionales-del-formato","link":"#campos-adicionales-del-formato","children":[]},{"level":2,"title":"Los formatos deben ser flexibles","slug":"los-formatos-deben-ser-flexibles","link":"#los-formatos-deben-ser-flexibles","children":[]}],"relativePath":"artifacts/product-backlog.md"}'),r={name:"artifacts/product-backlog.md"},l=i('<h1 id="pila-del-producto" tabindex="-1">Pila del Producto <a class="header-anchor" href="#pila-del-producto" aria-hidden="true">#</a></h1><blockquote><p>La Pila del Producto es, b\xE1sicamente, una lista priorizada de requisitos funcionales o Historias de Usuario. Cosas que el usuario quiere, descritas usando la terminolog\xEDa del usuario. Llamamos a esto historias, o a veces simplemente elementos de la Pila.</p></blockquote><p>La Pila del Producto es el inventario de funcionalidades, mejoras, tecnolog\xEDa y correcci\xF3n de errores que deben incorporarse al producto a trav\xE9s de los sucesivos Sprints. En \xE9l, el Due\xF1o del Producto, mantiene una lista actualizada de requerimientos funcionales para el software. Esta lista, representa <em><strong>\xABqu\xE9 es lo que se pretende\xBB</strong></em> pero sin mencionar <em><strong>\xABc\xF3mo hacerlo\xBB</strong></em>, ya que de esto \xFAltimo, se encargar\xE1 el equipo.</p><p>Esta pila representa todo aquello que esperan el Due\xF1o del Producto, todos los usuarios, y en general los interesados. Todo lo que suponga un trabajo que debe realizar el equipo debe estar reflejado en esta pila.</p><p><strong>Estos son algunos ejemplos de posibles entradas a una pila de producto</strong>:</p><ul><li>Permitir a los usuarios la consulta de las obras publicadas por un determinado autor.</li><li>Reducir el tiempo de instalaci\xF3n del programa.</li><li>Mejorar la escalabilidad del sistema.</li><li>Permitir la consulta de una obra a trav\xE9s de un API web.</li></ul><p><strong>La Pila del Producto, es creada y modificada \xFAnicamente por el Due\xF1o del Producto</strong>. Durante la ceremonia de planificaci\xF3n, el Equipo de Desarrollo obtendr\xE1 los items del producto, que deber\xE1 desarrollar durante el Sprint y de \xE9l, partir\xE1n para generar la Pila del Sprint.</p><blockquote><p><em>...\u201CLa Pila del Producto nunca est\xE1 completa. La primera versi\xF3n para el desarrollo, tan s\xF3lo establece los requisitos inicialmente conocidos, y que son entendidos mejor. La Pila del Producto evoluciona a medida que el producto y el entorno en el que se utilizar\xE1 evoluciona. La Pila del Producto es din\xE1mica, ya que cambia constantemente para identificar qu\xE9 necesita el producto para ser adecuado, competitivo y \xFAtil...\u201D (Scrum Guide, 2008, p\xE1g.18)</em></p></blockquote><p>La pila (de requisitos) del producto nunca se da por completada, al contrario, est\xE1 en continuo crecimiento y evoluci\xF3n. Al comenzar el proyecto incluye los requisitos inicialmente conocidos y mejor entendidos, y conforme avanza el desarrollo, y evoluciona el entorno en el que ser\xE1 usado, se va desarrollando. En definitiva su continuo dinamismo refleja aquello que el producto necesita incorporar para ser lo m\xE1s adecuado a las circunstancias, en todo momento.</p><p>Para comenzar el desarrollo se necesita la visi\xF3n del objetivo del negocio que se quiere conseguir con el proyecto, comprendido y conocido por todo el equipo, y los elementos suficientes en la pila para llevar a cabo el primer Sprint.</p><p>Habitualmente se comienza a elaborar la pila con el resultado de una reuni\xF3n de <em>\u201Ctormenta de ideas\u201D</em>, o un proceso de <em>\u201Cexploraci\xF3n\u201D</em> donde colabora todo el equipo partiendo de la visi\xF3n del Due\xF1o del Producto.</p><p>El formato de la visi\xF3n no es relevante. Seg\xFAn los casos, puede ser una presentaci\xF3n informal del responsable del producto, un informe de requisitos del departamento involucrado, u otros. Sin embargo, s\xED es importante disponer de una visi\xF3n real, comprendida y compartida por todo el equipo.</p><p>El propietario del producto mantiene la pila ordenada por la importancia de los elementos, siendo los m\xE1s prioritarios los que confieren mayor valor al producto, o por alguna raz\xF3n resultan m\xE1s necesarios, y determinan las actividades de desarrollo inmediatas.</p><p>El detalle de los requisitos en la Pila del Producto debe ser proporcional a la importancia (prioridad): Los elementos de mayor importancia deben tener mayor nivel de comprensi\xF3n y detalle que los del resto. De esta forma el Equipo de Desarrollo puede descomponer un elemento de alta importancia en tareas con la precisi\xF3n suficiente para ser hecho en un Sprint.</p><blockquote><p>Los elementos de la Pila del Producto que pueden ser incorporados a un Sprint se denominan \u201Cpreparados\u201D o \u201Caccionables\u201D y son los que pueden seleccionarse en la reuni\xF3n de planificaci\xF3n del Sprint.</p></blockquote><h2 id="preparacion-de-la-pila-del-producto" tabindex="-1">Preparaci\xF3n de la Pila del Producto <a class="header-anchor" href="#preparacion-de-la-pila-del-producto" aria-hidden="true">#</a></h2><p>Se denomina \u201Cpreparaci\xF3n\u201D (grooming) de la Pila del Producto a las actividades de priorizaci\xF3n, detalle y estimaci\xF3n de los elementos que la componen. Es un proceso que realizan de forma puntual, en cualquier momento, continua y colaborativa, el Due\xF1o del Producto y el Equipo de Desarrollo. No debe consumir m\xE1s del 10% de la capacidad de trabajo del equipo.</p><p>La responsabilidad de estimar el esfuerzo previsible para cada elemento, es de las personas del equipo que previsiblemente har\xE1n el trabajo.</p><h2 id="formato-de-la-pila-del-producto" tabindex="-1">Formato de la Pila del Producto <a class="header-anchor" href="#formato-de-la-pila-del-producto" aria-hidden="true">#</a></h2><p>El agilismo propone y prefiere la comunicaci\xF3n verbal o de visualizaci\xF3n directa, a la escrita. La Pila del Producto no es un documento formal de requisitos, sino un artefacto de referencia para el equipo. La Pila del Producto, es una lista de items que representan los requerimientos funcionales esperados para el software.</p><p>Si se emplea formato de lista, es recomendable que al menos incluya la siguiente informaci\xF3n para cada elemento:</p><ul><li>Id.</li><li>Grado de Importancia.</li><li>Descripci\xF3n (de funcionalidad/requisito, denominado \u201CHistoria de Usuario\u201D).</li><li>Esfuerzo que demanda.</li><li>Granulidad de los Items.</li><li>Criterios de aceptaci\xF3n.</li><li>Notas (Observaci\xF3n)</li></ul><h2 id="id" tabindex="-1">Id <a class="header-anchor" href="#id" aria-hidden="true">#</a></h2><p>Es un identificador \xFAnico, simplemente un n\xFAmero auto-incremental. Esto nos permite no perder la pista a las historias cuando cambiamos su nombre.</p><h2 id="grado-de-importancia" tabindex="-1">Grado de Importancia <a class="header-anchor" href="#grado-de-importancia" aria-hidden="true">#</a></h2><p>Los items de la Pila del Producto, deben guardar un orden de importancia y para que el Due\xF1o del Producto logre establecer el Grado de Importancia, debe apoyarse en la siguiente base:</p><ul><li>Riesgos de implementarla.</li><li>Coherencia con los intereses del negocio.</li><li>Beneficios de implementar una funcionalidad.</li><li>Valor diferencial con respecto a productos de la competencia.</li><li>P\xE9rdida o costo que demande posponer la implementaci\xF3n de una funcionalidad.</li></ul><p>El grado de importancia que el Due\xF1o del Producto le da a la Historia de Usuario debe ser, que mientras m\xE1s alto es, igual a m\xE1s importante.</p><blockquote><p><strong>Henrik Kniberg</strong>: <em>Suelo evitar el t\xE9rmino \u201Cprioridad\u201D porque t\xEDpicamente \u201C1\u201D se considera la m\xE1xima prioridad, lo que es muy inc\xF3modo si posteriormente se decide que algo es m\xE1s importante. \xBFQu\xE9 prioridad le dar\xEDamos a ese nuevo elemento? \xBFPrioridad 0? \xBFPrioridad -1?</em></p></blockquote><p>Todos los elementos importantes deber\xEDan tener diferentes grados de importancia asignados. En realidad, da igual si los elementos menos importantes tienen todos el mismo valor, ya que probablemente no se discutir\xE1n durante la planificaci\xF3n de Sprint en cualquier caso.</p><p>Cualquier historia sobre la que el Due\xF1o del Producto piense que tiene una remota posibilidad de incluirse en el Sprint deber\xEDa tener un nivel de importancia \xFAnico definido. El grado de importancia se emplea solo para ordenar los elementos por relevancia. As\xED que si el elemento A tiene una importancia de 20 y el elemento B una importancia de 100, simplemente significa que B es m\xE1s importante que A. No significa que B sea cinco veces m\xE1s importante que A. Si B tuviera una importancia de 21, \xA1aun significar\xEDa lo mismo! Es \xFAtil dejar espacio entre la secuencia de n\xFAmeros por si aparece un elemento C que es m\xE1s importante que A pero menos importante que B. Por supuesto, le podr\xEDamos dar un grado de importancia de 20,5 a C, pero en vez de ello se aconseja dejar espacio entre n\xFAmeros.</p><p>Otras personas aparte del Due\xF1o del Producto pueden a\xF1adir sus historias a la Pila de Producto. Pero no pueden asignarles niveles de importancia, ese es un cometido exclusivo del Due\xF1o del Producto. Tampoco pueden establecer estimaciones, ese es un cometido exclusivo del equipo.</p><h2 id="descripcion" tabindex="-1">Descripci\xF3n <a class="header-anchor" href="#descripcion" aria-hidden="true">#</a></h2><blockquote><p>Consiste en la descripci\xF3n breve de la funcionalidad (requisito), denominada \u201CHistoria de Usuario\u201D.</p></blockquote><p>Se trata de una descripci\xF3n corta de la historia, suficientemente clara como para que el Due\xF1o del Producto comprenda aproximadamente de qu\xE9 estamos hablando, y suficientemente clara como para distinguirla de las otras historias.</p><p>Normalmente, 2 a 10 palabras.</p><p>Por ejemplo: <strong><em>\u201CVisualizar historial de transacciones\u201D</em></strong>.</p><h2 id="esfuerzo-que-demanda" tabindex="-1">Esfuerzo que demanda <a class="header-anchor" href="#esfuerzo-que-demanda" aria-hidden="true">#</a></h2><p>A diferencia de las metodolog\xEDas tradicionales, Scrum, propone la estimaci\xF3n de esfuerzo y complejidad que demanda el desarrollo de las funcionalidades, solo para aquellas cuyo orden sea prioritario.</p><p>Estas estimaciones, no se efect\xFAan sobre items poco prioritarios ni tampoco sobre aquellos donde exista un alto grado de incertidumbre. De esta manera, se evita la p\xE9rdida de tiempo en estimaciones irrelevantes, posterg\xE1ndolas para el momento en el cual realmente sea necesario comenzar a desarrollarlas.</p><blockquote><p><em>\u201CEl equipo da al Due\xF1o del Producto las estimaciones del esfuerzo requerido para cada elemento de la Pila del Producto. Adem\xE1s, el Due\xF1o del Producto es responsable de asignar una estimaci\xF3n del valor del negocio a cada elemento individual. Esto es normalmente una pr\xE1ctica desconocida para el Due\xF1o del Producto. Por esa raz\xF3n, a veces el Gestor del Proyecto puede ense\xF1ar al Due\xF1o del Producto a hacerlo.\u201D</em> (The Scrum Primer, 2009, p\xE1g. 8)</p></blockquote><h2 id="granulidad-de-los-items" tabindex="-1">Granulidad de los Items <a class="header-anchor" href="#granulidad-de-los-items" aria-hidden="true">#</a></h2><p>Los items de la Pila del Producto no necesariamente deben tener una granulidad pareja. Es posible encontrar \xEDtems tales como <em>&quot;es necesario contar con un m\xF3dulo de control de stock y log\xEDstica&quot;</em> o uno tan peque\xF1o como <em>&quot;Modificar el color de fondo de los mensajes de error del sistema, de negro a rojo&quot;</em>.</p><blockquote><p><em>\u201C... Los \xCDtems de tan baja granulidad, suelen agruparse en un formato denominado \xABHistorias de Usuario\xBB mientras que los de alta granulidad, suelen llamarse \xABtemas\xBB. Cuando los elementos de la Pila del Producto han sido preparados con este nivel de granularidad, los que est\xE1n en la parte superior del mismo (los de mayor prioridad, y mayor valor) se descomponen para que quepan en un Sprint...\u201D</em> (Scrum Guide, 2008, p\xE1g.19)</p></blockquote><h2 id="criterios-de-aceptacion" tabindex="-1">Criterios de Aceptaci\xF3n <a class="header-anchor" href="#criterios-de-aceptacion" aria-hidden="true">#</a></h2><p>Es recomendable que cada \xEDtem de la Pila del Producto, especifique cuales son los criterios de aceptaci\xF3n (o prueba de aceptaci\xF3n que debe superar), para considerar cumplido el requisito.</p><p>Los criterios de aceptaci\xF3n, entonces, no son m\xE1s que <em>\u201Cpautas\u201D</em> o peque\xF1as <em>\u201Creglas\u201D</em> que una Historia de Usuario debe respetar para considerarla cumplida.</p><p>Por ejemplo, para la Historia de Usuario <em>\xABComo administrador del sistema necesito agregar productos al cat\xE1logo\xBB</em>, los criterios de aceptaci\xF3n podr\xEDan ser:</p><ul><li>Cada producto debe contener: <ul><li>c\xF3digo de producto (opcional).</li><li>descripci\xF3n de hasta 500 caracteres (opcional).</li><li>precio (obligatorio).</li><li>stock inicial (opcional).</li><li>un nombre (obligatorio).</li><li>una foto (opcional).</li></ul></li><li>No pueden existir dos productos con el mismo nombre de producto o c\xF3digo de producto.</li><li>El nombre del producto jam\xE1s puede estar vac\xEDo o tener menos de 3 caracteres.</li><li>Cuando no se asigne un stock inicial al producto, \xE9ste debe asignarse autom\xE1ticamente en cero (sin stock).</li></ul><blockquote><p><em>\u201C... Las Pruebas de Aceptaci\xF3n se utilizan a menudo como un atributo m\xE1s de la Pila del Producto. A menudo pueden sustituir a descripciones de texto m\xE1s detalladas, que contengan una descripci\xF3n comprobable, de lo que el elemento de la Pila del Producto debe hacer cuando est\xE9 completado...\u201D</em> (Scrum Guide, 2008, p\xE1g.19)</p></blockquote><h2 id="notas-observacion" tabindex="-1">Notas (Observaci\xF3n) <a class="header-anchor" href="#notas-observacion" aria-hidden="true">#</a></h2><p>Colocamos cualquier otra informaci\xF3n, clarificaci\xF3n, referencia a otras fuentes de informaci\xF3n, etc. Normalmente muy breves.</p><h2 id="campos-adicionales-del-formato" tabindex="-1">Campos adicionales del formato <a class="header-anchor" href="#campos-adicionales-del-formato" aria-hidden="true">#</a></h2><p>A veces se utiliza campos adicionales en la Pila del Producto, fundamentalmente como comodidad para el Due\xF1o del Producto a la hora de decidir sus prioridades. Dependiendo del tipo de proyecto, funcionamiento del equipo y la organizaci\xF3n, pueden ser aconsejables otros campos:</p><ul><li>Persona asignada.</li><li>N\xB0 de Sprint en el que se realiza.</li><li>M\xF3dulo del sistema al que pertenece.</li><li>Solicitante.</li><li>Entre otros.</li></ul><h2 id="los-formatos-deben-ser-flexibles" tabindex="-1">Los formatos deben ser flexibles <a class="header-anchor" href="#los-formatos-deben-ser-flexibles" aria-hidden="true">#</a></h2><p>Es preferible no adoptar formatos r\xEDgidos, ya que los resultados del agilismo no dependen de las formas, sino de la institucionalizaci\xF3n de sus principios y la implementaci\xF3n adecuada a las caracter\xEDsticas de la empresa y del proyecto. He aqu\xED un sencillo ejemplo de Pila del Producto:</p><table><thead><tr><th style="text-align:center;">Importancia</th><th style="text-align:left;">Descripci\xF3n</th><th style="text-align:center;">Esfuerzo</th><th style="text-align:center;">Elaborado por</th></tr></thead><tbody><tr><td style="text-align:center;">90</td><td style="text-align:left;">Plataforma tecnol\xF3gica</td><td style="text-align:center;">XL</td><td style="text-align:center;">A.R.</td></tr><tr><td style="text-align:center;">70</td><td style="text-align:left;">Interfaz de usuario</td><td style="text-align:center;">L</td><td style="text-align:center;">L.M.</td></tr><tr><td style="text-align:center;">60</td><td style="text-align:left;">Un usuario se registra en el sistema</td><td style="text-align:center;">S</td><td style="text-align:center;">C.C.</td></tr><tr><td style="text-align:center;">40</td><td style="text-align:left;">El operador define el flujo y textos de un expediente</td><td style="text-align:center;">S</td><td style="text-align:center;">J.H.</td></tr><tr><td style="text-align:center;">30</td><td style="text-align:left;">xxx</td><td style="text-align:center;">M</td><td style="text-align:center;">A.R.</td></tr></tbody></table><p>Mantenemos esta tabla en una Hoja de C\xE1lculo con <em>\u201Ccompartir\u201D</em> habilitado (es decir, muchos usuarios pueden editar simult\xE1neamente la hoja). Oficialmente, el Due\xF1o del Producto es el propietario del documento, pero no queremos dejar al resto de usuarios fuera. Muchas veces un desarrollador necesita abrir el documento para clarificar algo o cambiar una estimaci\xF3n de esfuerzo.</p><p>Por la misma raz\xF3n, no se coloca este documento en el repositorio de control de versiones; en vez de eso, lo almacenamos en una unidad de red compartida. Esta ha demostrado ser la manera m\xE1s simple de permitir m\xFAltiples editores diferentes sin causar problemas de bloqueo o fusi\xF3n de documentos. Sin embargo, casi todos los dem\xE1s artefactos se colocan en el repositorio de control de versiones.</p>',60),t=[l];function d(n,s,c,u,p,m){return o(),a("div",null,t)}const g=e(r,[["render",d]]);export{f as __pageData,g as default};
